package com.example.cms.attachment;
import com.example.cms.attachment.storage.FileStorageService;import org.springframework.stereotype.Service;import java.io.*;import java.util.*;
@Service
public class AttachmentService { private final AttachmentRepository repo; private final AttachmentValidationService validation; private final FileStorageService storage; public AttachmentService(AttachmentRepository repo,AttachmentValidationService validation,FileStorageService storage){this.repo=repo;this.validation=validation;this.storage=storage;} public AttachmentDto register(Long doc,String name,long size,String mime)throws IOException{validation.validate(name,size,mime);String key=storage.store(name,new ByteArrayInputStream(new byte[]{1}));String ext=name.substring(name.lastIndexOf('.')+1).toLowerCase();return repo.save(doc,name,key,size,ext,mime);} public List<AttachmentDto> list(Long doc){return repo.list(doc);} public AttachmentDto get(Long id){return repo.get(id);} public void delete(Long id){repo.delete(id);} }
